questionvariables.text:
/* 1. Randomized Distances for a Hiker */
d_east: 6 + rand(7);    /* East distance: 6 to 12 km */
d_north: 5 + rand(6);   /* North distance: 5 to 10 km */

/* 2. Calculations */
/* Scalar sum for total distance */
total_dist: d_east + d_north;

/* Vector resultant for displacement */
disp_sq: (d_east^2) + (d_north^2);
displacement: sqrt(disp_sq);

/* 3. Teacher Answers */
ta1: total_dist;
ta2: displacement;
